1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns premium of 5 G for an empty item list (processing fee only)", () => {
7	      const scenario = {
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      };
11	      const result = processScenario(scenario);
12	      expect(result.results[0]).toEqual({ premium: 5 });
13	    });
14	    it.todo("returns correct base premium for a single sword (100 G + 5 G fee = 105 G)");
15	    it.todo("returns correct base premium for a single amulet (60 G + 5 G fee = 65 G)");
16	    it.todo("returns correct base premium for a single staff (80 G + 5 G fee = 85 G)");
17	    it.todo("returns correct base premium for a single potion (40 G + 5 G fee = 45 G)");
18	    it.todo("returns correct base premium for a single component (25 G + 5 G fee = 30 G)");
19	    it.todo("sums base premiums for multiple items in a policy");
20	  });
21	
22	  describe("Quote - component blocks", () => {
23	    it.todo("charges 50 G for 2 runes (no block)");
24	    it.todo("charges 60 G for exactly 3 alike components (block applies)");
25	    it.todo("charges 100 G for 4 runes (no block — block requires exactly 3)");
26	    it.todo("charges 75 G for 2 runes + 1 moonstone (no block: different types)");
27	    it.todo("charges 120 G for 3 runes + 3 moonstones (two separate blocks)");
28	    it.todo("charges 175 G for 7 runes (no blocks apply)");
29	  });
30	
31	  describe("Quote - item-specific modifiers", () => {
32	    it.todo("adds 50% cursed surcharge on the cursed item's base premium only");
33	    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
34	    it.todo("applies both cursed and high-enchantment surcharges on the same item");
35	    it.todo("does not add high-enchantment surcharge for enchantment level 4");
36	    it.todo("applies item-specific surcharges only to affected items in multi-item policy");
37	  });
38	
39	  describe("Quote - policy-wide modifiers", () => {
40	    it.todo("adds 10% first insurance surcharge on policy base premium");
41	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
42	    it.todo("applies 15% follow-up discount on second and subsequent contracts");
43	    it.todo("does not apply loyalty discount for customer with < 2 years");
44	  });
45	
46	  describe("Quote - integration: modifier stacking", () => {
47	    it.todo("newcomer with cursed sword: 100 + 50 curse + 10 first = 160 + 5 fee = 165 G");
48	    it.todo("long-standing second contract cursed enchanted sword: 100 + 50 + 30 - 20 + 10 - 15 = 155 + 5 = 160 G");
49	    it.todo("rounds premium up in MHPCO's favor");
50	  });
51	
52	  describe("Quote - error handling", () => {
53	    it.todo("rejects unknown item type with an error");
54	  });
55	
56	  describe("Claim - standard reimbursement", () => {
57	    it.todo("reimburses damage minus 100 G deductible for a standard item");
58	    it.todo("applies deductible per damaged item in same event");
59	    it.todo("reimburses damage to a component minus deductible");
60	  });
61	
62	  describe("Claim - special clauses", () => {
63	    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
64	    it.todo("fully reimburses dragon-material items minus deductible");
65	    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
66	    it.todo("fully reimburses dragon-material with enchantment < 8 minus deductible");
67	  });
68	
69	  describe("Claim - cap tracking", () => {
70	    it.todo("caps total payout at 2x insurance sum per policy");
71	    it.todo("tracks remaining cap across multiple claims on same policy");
72	    it.todo("reduces payout to remaining cap when cap is nearly exhausted");
73	  });
74	
75	  describe("Claim - error handling", () => {
76	    it.todo("rejects claim referencing item not in the policy");
77	    it.todo("rejects claim with negative damage amount");
78	    it.todo("rejects claim with more damages of a type than policy covers");
79	  });
80	});
81

